; EarthBound C2 loaded enemy sprite list width-budget trimmer.
;
; Source-emission status:
; - Prototype level: build-candidate
; - Generated by tools/emit_linear_source_module.py from a state-aware
;   linear ROM decode, then intended for byte-equivalence validation.
;
; Source units covered:
; - C2:F0D1..C2:F121 TrimLoadedEnemySpriteListToWidthLimit
;
; Runtime contract:
; - Keeps the staged enemy sprite list within the total row-width budget.
; - Iterates `$9F8C[0..$9F8A)`, maps each entry through the D5 enemy config
;   battle sprite id, calls the local width helper, and truncates `$9F8A` when
;   accumulated width would exceed `0x20`.

; ---------------------------------------------------------------------------
; External contracts used by this module

C08FF7_ResolveIndexedPointerOffset = $C08FF7
C2EFFD_GetBattleSpriteWidthBucket  = $EFFD

; ---------------------------------------------------------------------------
; C2:F0D1

C2F0D1_TrimLoadedEnemySpriteListToWidthLimit:
    rep #$31
    phd
    tdc
    adc.w #$FFEE
    tcd
    ldy.w #$0000
    sty $10
    tyx
    stx $0E
    bra C2F11A_TrimLoadedEnemySpriteListToWidthLimit_LF11A
C2F0E3_TrimLoadedEnemySpriteListToWidthLimit_LF0E3:
    txa
    asl A
    tax
    ; Staged enemy list entry -> enemy config -> battle sprite id.
    lda $9F8C,X
    ldy.w #$005E
    jsl C08FF7_ResolveIndexedPointerOffset
    clc
    adc.w #$001C
    tax
    lda $D59589,X
    ; Width helper returns the sprite's layout width in 8x8-tile units.
    jsr C2EFFD_GetBattleSpriteWidthBucket
    sta $02
    ldy $10
    tya
    clc
    adc $02
    tay
    sty $10
    cpy.w #$0020
    bcc C2F115_TrimLoadedEnemySpriteListToWidthLimit_LF115
    beq C2F115_TrimLoadedEnemySpriteListToWidthLimit_LF115
    ; Over budget: keep only entries before the first overflowing sprite.
    ldx $0E
    stx $9F8A
    bra C2F11F_TrimLoadedEnemySpriteListToWidthLimit_LF11F
C2F115_TrimLoadedEnemySpriteListToWidthLimit_LF115:
    ldx $0E
    inx
    stx $0E
C2F11A_TrimLoadedEnemySpriteListToWidthLimit_LF11A:
    cpx $9F8A
    bcc C2F0E3_TrimLoadedEnemySpriteListToWidthLimit_LF0E3
C2F11F_TrimLoadedEnemySpriteListToWidthLimit_LF11F:
    pld
    rtl
